(415, 388, 40, 'https://yamaha-ai-generations-2026.s3.ap-south-1.amazonaws.com/generations/gen_75ef97bf4c3bac085a25855e20f49e4d.jpg', '{\"behavior\":12,\"destination_id\":723,\"destination\":\"Canada\",\"destination_meta\":{\"country\":\"Canada\",\"country_bn\":\"কানাডা\",\"jersey_colors\":\"vibrant red and white\",\"theme_colors\":\"red and white\",\"stadium\":\"BC Place Stadium\",\"personality\":\"Proud Canada supporter, red and white football spirit.\",\"personality_bn\":\"গর্বিত কানাডা সমর্থক, ফুটবল উদ্দীপনা।\",\"scene\":\"Outside BC Place Stadium, damp pavement, soft stadium lighting. Canada flag in the sky. blurred crowds in the distant background wearing vibrant red and white jerseys. red and white confetti. festive banners.\"},\"aspiration_id\":7,\"aspiration\":\"Freedom Rider\",\"aspiration_meta\":{\"color\":\"Blue\"}}', 'The spirited convergence of Canadian pride and the agile precision of the Yamaha MT-15 captures the essence of a rider unbound by convention. This portrait elevates the freedom of the open road into a sophisticated narrative of national devotion and mechanical grace.', '2026-06-12 15:47:11', '75ef97bf4c3bac085a25855e20f49e4d', 'completed', 12, 723, 7, 'Blue', '{\"strategy\":\"weighted_distribution_with_color_bonus\",\"aspiration_color\":\"Blue\",\"total_behavior_generations\":55,\"candidates\":[{\"bike_id\":40,\"model_name\":\"Yamaha MT 15\",\"weight_percent\":20,\"priority_order\":2,\"assigned_count\":10,\"matched_color\":\"Blue\",\"color_match\":true,\"deficit\":1.2,\"final_score\":1.352},{\"bike_id\":35,\"model_name\":\"Yamaha FZ-25\",\"weight_percent\":20,\"priority_order\":3,\"assigned_count\":10,\"matched_color\":\"Racing Blue\",\"color_match\":true,\"deficit\":1.2,\"final_score\":1.352},{\"bike_id\":38,\"model_name\":\"Yamaha FZS FI V4\",\"weight_percent\":20,\"priority_order\":5,\"assigned_count\":10,\"matched_color\":\"Racing Blue\",\"color_match\":true,\"deficit\":1.2,\"final_score\":1.3519},{\"bike_id\":37,\"model_name\":\"Yamah